// HasEmpresa applies the HasEdge predicate on the "empresa" edge.
func HasEmpresa() predicate.Pago {
	return predicate.Pago(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, EmpresaTable, EmpresaColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasEmpresaWith applies the HasEdge predicate on the "empresa" edge with a given conditions (other predicates).
func HasEmpresaWith(preds ...predicate.Empresa) predicate.Pago {
	return predicate.Pago(func(s *sql.Selector) {
		step := newEmpresaStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

